from itertools import product

def enc4x2(D0, D1, D2, D3):
    return D1 | D3, D2 | D3  # Y0, Y1

for i, expected in enumerate([(0,0),(1,0),(0,1),(1,1)]):
    D = [0, 0, 0, 0]
    D[i] = 1
    assert enc4x2(*D) == expected
print("4x2 인코더: Di=1일 때 Y1Y0이 i의 2비트 값과 일치")

def enc8x3(D):
    Y0 = D[1] | D[3] | D[5] | D[7]
    Y1 = D[2] | D[3] | D[6] | D[7]
    Y2 = D[4] | D[5] | D[6] | D[7]
    return Y0, Y1, Y2

for i in range(8):
    D = [0] * 8
    D[i] = 1
    Y0, Y1, Y2 = enc8x3(D)
    assert Y2 * 4 + Y1 * 2 + Y0 == i
print("8x3 인코더: Di=1일 때 출력이 i의 3비트 값과 일치")

def dec2x4(A, B):
    return (1-A)*(1-B), (1-A)*B, A*(1-B), A*B  # Y0..Y3

def dec3x8(A, B, C):
    idx = A*4 + B*2 + C
    return tuple(1 if i == idx else 0 for i in range(8))

for A, B in product([0, 1], repeat=2):
    assert sum(dec2x4(A, B)) == 1
for A, B, C in product([0, 1], repeat=3):
    assert sum(dec3x8(A, B, C)) == 1
print("2x4, 3x8 디코더 모두 각 입력 조합에서 출력이 정확히 하나만 1임을 확인")
